import { isNil } from 'lodash-es';

export const getColorFromToken = (token: string) => {
  const documentRoot = document.documentElement;
  if (isNil(documentRoot)) {
    return;
  }

  const computedStyles = getComputedStyle(documentRoot);
  const cssVariableName = token.split(',')[0].replace('var(', '');

  return computedStyles.getPropertyValue(cssVariableName);
};
